from hydpy.exe.modelimports import *
from hydpy.core import devicetools
from hydpy.core import modeltools
from hydpy.core import objecttools
from hydpy.core.typingtools import *
from hydpy.models.manager import manager_model


class Model(modeltools.AdHocModel):
    """|manager_lwc.DOCNAME.complete|.

    |manager_lwc| relies on a name-based mechanism to build connections to the relevant
    nodes of the instructable source elements.  See the integration test setup for a
    realistic setting.  Here, we focus on testing and demonstrating the handling of
    potentially problematic specifications:

    .. testsetup::

        >>> from hydpy import Element, Node
        >>> Node.clear_all()
        >>> Element.clear_all()

    >>> from hydpy.models.manager_lwc import *
    >>> parameterstep()
    >>> sources("d1")

    >>> from hydpy import Element, FusedVariable, Node, Nodes
    >>> from hydpy.aliases import (
    ...     dam_observers_A,
    ...     dam_states_WaterVolume,
    ...     manager_senders_Request,
    ...     manager_receivers_WaterVolume,
    ... )
    >>> lwc = Element("lwc")
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
is no source element named `d1` available.

    >>> from hydpy.aliases import manager_receivers_WaterVolume
    >>> v1 = Node("v1", variable=manager_receivers_WaterVolume)
    >>> d1 = Element("d1", outlets="q1", outputs=v1)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
must be exactly one node that informs about the current water volume of the source \
element `d1`, but no such nodes are available.

    >>> lwc.receivers.add_device(v1, force=True)
    >>> sources("d1", "d2")
    >>> d2 = Element("d2", outlets="q2", outputs="v2")
    >>> lwc.receivers.add_device("v2", force=True)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
must be exactly one node that informs about the current water volume of the source \
element `d2`, but no such nodes are available.

    >>> lwc.receivers.remove_device("v2", force=True)
    >>> v2a, v2b = Nodes("v2a", "v2b", defaultvariable=manager_receivers_WaterVolume)
    >>> d2.outputs.add_device(v2a, force=True)
    >>> d2.outputs.add_device(v2b, force=True)
    >>> lwc.receivers.add_device(v2a, force=True)
    >>> lwc.receivers.add_device(v2b, force=True)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
must be exactly one node that informs about the current water volume of the source \
element `d2`, but two such nodes are available (`v2a` and `v2b`).

    >>> sources("d1")
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
must be exactly one node that reports the current discharge at the target location, \
but no such nodes are available.

    >>> t = Node("t")
    >>> lwc.receivers.add_device(t, force=True)
    >>> lwc.receivers.add_device("target", force=True)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
must be exactly one node that reports the current discharge at the target location, \
but two such nodes are available (`t` and `target`).

    >>> lwc.receivers.remove_device("target", force=True)
    >>> from hydpy.aliases import manager_senders_Request
    >>> r1 = Node("r1", variable=manager_senders_Request)
    >>> d1.observers.add_device(r1, force=True)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `sender` sequences \
of the model handled by element `lwc`, the following error occurred: There must be \
exactly one node that informs the source element `d1` about the request for \
additional water release, but no such nodes are available.

    >>> lwc.senders.add_device(r1, force=True)
    >>> sources("d1", "d3")
    >>> d3 = Element("d3", outlets="q3", observers="r3")
    >>> lwc.receivers.add_device("r3", force=True)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `receiver` \
sequences of the model handled by element `lwc`, the following error occurred: There \
must be exactly one node that informs about the current water volume of the source \
element `d3`, but no such nodes are available.

    >>> lwc.receivers.remove_device("r3", force=True)
    >>> from hydpy.aliases import manager_senders_Request
    >>> r3a, r3b = Nodes("r3a", "r3b", defaultvariable=manager_senders_Request)
    >>> d3.outputs.add_device(v2a, force=True)
    >>> d3.observers.add_device(r3a, force=True)
    >>> d3.observers.add_device(r3b, force=True)
    >>> lwc.senders.add_device(r3a, force=True)
    >>> lwc.senders.add_device(r3b, force=True)
    >>> lwc.model = model
    Traceback (most recent call last):
    ...
    RuntimeError: While trying to build the node connection of the `sender` sequences \
of the model handled by element `lwc`, the following error occurred: There must be \
exactly one node that informs the source element `d3` about the request for \
additional water release, but two such nodes are available (`r3a` and `r3b`).

    >>> sources("d1", "d4")
    >>> v4 = Node("v4", variable=manager_receivers_WaterVolume)
    >>> r4 = Node("r4", variable=manager_senders_Request)
    >>> d4 = Element("d4", outputs=v4, observers=r4)
    >>> lwc.receivers.add_device(v4, force=True)
    >>> lwc.senders.add_device(r4, force=True)
    >>> lwc.model = model

    >>> fluxes.request = 1.0, 2.0
    >>> model.update_senders()
    >>> r1.sequences.sim
    sim(1.0)
    >>> r4.sequences.sim
    sim(2.0)

    >>> t.sequences.sim = 1.0
    >>> derived.memorylength(1)
    >>> v1.sequences.sim = 2.0
    >>> v4.sequences.sim = 3.0
    >>> model.update_receivers(0)
    >>> logs.loggeddischarge
    loggeddischarge(1.0)
    >>> logs.loggedwatervolume
    loggedwatervolume(d1=2.0, d4=3.0)
    """

    DOCNAME = modeltools.DocName(
        short="Manager-LWC", description="low water control management model"
    )
    __HYDPY_ROOTMODEL__ = True

    INLET_METHODS = ()
    OBSERVER_METHODS = ()
    RECEIVER_METHODS = (
        manager_model.Pick_LoggedDischarge_V1,
        manager_model.Pick_LoggedWaterVolume_V1,
    )
    RUN_METHODS = (
        manager_model.Calc_FreeDischarge_V1,
        manager_model.Calc_DemandTarget_V1,
        manager_model.Calc_Alertness_V1,
        manager_model.Calc_DemandSources_V1,
        manager_model.Calc_PossibleRelease_V1,
        manager_model.Calc_Request_V1,
        manager_model.Update_LoggedRequest_V1,
    )
    ADD_METHODS = ()
    OUTLET_METHODS = ()
    SENDER_METHODS = (manager_model.Pass_Request_V1,)
    SUBMODELINTERFACES = ()
    SUBMODELS = ()

    @staticmethod
    def _get_error_message_suffix(nodes: list[devicetools.Node]) -> str:
        if nodes:
            return f" ({objecttools.enumeration(f'`{s.name}`' for s in nodes)})"
        return ""

    def _connect_receivers(self, report_noconnect: bool = True) -> None:

        registry = devicetools._registry  # pylint: disable=protected-access
        name2elements = cast(
            dict[str, devicetools.Element], registry[devicetools.Element]
        )

        sources = self.parameters.control.sources
        volume_nodes = []
        watervolume = self.sequences.receivers.watervolume
        for sourcename in sources.sourcenames:
            element = name2elements.get(sourcename, None)
            if element is None:
                raise RuntimeError(
                    f"There is no source element named `{sourcename}` available."
                )
            selected = [
                n
                for n in itertools.chain(element.outputs, element.senders)
                if ((n in self.element.receivers) and (n.variable == type(watervolume)))
            ]
            if (n := len(selected)) != 1:
                selected_ = self._get_error_message_suffix(selected)
                e = inflect.engine()
                number = e.number_to_words(n, zero="no")  # type: ignore[arg-type]
                raise RuntimeError(
                    f"There must be exactly one node that informs about the "
                    f"current water volume of the source element `{sourcename}`, but "
                    f"{number} such nodes are available{selected_}."
                )
            volume_nodes.append(selected[0])
        watervolume.connect_to_nodes(
            group="receivers",
            available_nodes=volume_nodes,
            applied_nodes=[],
            report_noconnect=report_noconnect,
        )

        target_nodes = [n for n in self.element.receivers if n.variable == "Q"]
        if (n := len(target_nodes)) != 1:
            selected_ = self._get_error_message_suffix(target_nodes)
            e = inflect.engine()
            number = e.number_to_words(n, zero="no")  # type: ignore[arg-type]
            raise RuntimeError(
                f"There must be exactly one node that reports the current discharge "
                f"at the target location, but {number} such nodes are available"
                f"{selected_}."
            )
        self.sequences.receivers.q.connect_to_nodes(
            group="receivers",
            available_nodes=target_nodes,
            applied_nodes=[],
            report_noconnect=report_noconnect,
        )

    def _connect_senders(self, report_noconnect: bool = True) -> None:

        registry = devicetools._registry  # pylint: disable=protected-access
        name2elements = cast(
            dict[str, devicetools.Element], registry[devicetools.Element]
        )

        sources = self.parameters.control.sources
        request_nodes = []
        request = self.sequences.senders.request
        for sourcename in sources.sourcenames:
            element = name2elements[sourcename]
            selected = [
                n
                for n in element.observers
                if ((n in self.element.senders) and (n.variable == type(request)))
            ]
            if (n := len(selected)) != 1:
                selected_ = self._get_error_message_suffix(selected)
                e = inflect.engine()
                number = e.number_to_words(n, zero="no")  # type: ignore[arg-type]
                raise RuntimeError(
                    f"There must be exactly one node that informs the source element "
                    f"`{sourcename}` about the request for additional water release, "
                    f"but {number} such nodes are available{selected_}."
                )
            request_nodes.append(selected[0])
        request.connect_to_nodes(
            group="senders",
            available_nodes=request_nodes,
            applied_nodes=[],
            report_noconnect=report_noconnect,
        )


tester = Tester()
cythonizer = Cythonizer()
